css:
.loader {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
  width: 60px;
  aspect-ratio: 1;
  display: flex;
  animation: l11-0 2s infinite linear;
}.loader::before,.loader::after {content:"";
  flex:1;
  clip-path: polygon(100% 0,100% 100%,0 50%);
  animation:l11-1 1s infinite linear alternate,l11-2 2s infinite linear -.5s;
}.loader::after {--s:-1,-1;
}@keyframes l11-0 {0%,49.99% {transform: scaleX(1) rotate(0deg)}50%,100% {transform: scaleX(-1) rotate(-90deg)}}@keyframes l11-1 {0%,5% {transform: scale(var(--s,1)) translate(0px) perspective(150px) rotateY(0deg) }33% {transform: scale(var(--s,1)) translate(-10px) perspective(150px) rotateX(0deg) }66% {transform: scale(var(--s,1)) translate(-10px) perspective(150px) rotateX(-180deg)}95%,100% {transform: scale(var(--s,1)) translate(0px) perspective(150px) rotateX(-180deg)}}@keyframes l11-2 {0%,49.99% {background:var(--loader-secondary-color, #a5b4fc)}50%,100% {background:var(--loader-secondary-color, #a5b4fc)}}
